package com.hospital.management.filter;
import com.hospital.management.dao.AuditLogDao;import com.hospital.management.dao.impl.AuditLogDaoImpl;import com.hospital.management.model.AuthenticatedUser;import javax.servlet.*;import javax.servlet.annotation.WebFilter;import javax.servlet.http.*;import java.io.IOException;import java.util.*;
/** Path-level role guard; appointment ownership is additionally enforced by AppointmentService. */
@WebFilter(urlPatterns={"/admin/*","/doctor/*","/nurse/*","/reception/*","/patient/*","/billing/*","/schedules","/schedules/*","/appointments","/appointments/*"})
public class RoleAuthorizationFilter implements Filter {private static final Map<String,Set<String>>ACCESS=Map.of("/admin/",Set.of("ADMIN"),"/doctor/",Set.of("DOCTOR","ADMIN"),"/nurse/",Set.of("NURSE","ADMIN"),"/reception/",Set.of("RECEPTIONIST","ADMIN"),"/patient/",Set.of("PATIENT","ADMIN"),"/billing/",Set.of("BILLING_STAFF","ADMIN"));private final AuditLogDao audit;public RoleAuthorizationFilter(){this(new AuditLogDaoImpl());}public RoleAuthorizationFilter(AuditLogDao a){audit=a;}
public void doFilter(ServletRequest a,ServletResponse b,FilterChain c)throws IOException,ServletException{HttpServletRequest q=(HttpServletRequest)a;HttpServletResponse r=(HttpServletResponse)b;String path=q.getRequestURI().substring(q.getContextPath().length());HttpSession s=q.getSession(false);if(s==null||!(s.getAttribute("authenticatedUser") instanceof AuthenticatedUser u)){if(path.equals("/appointments/slots")){r.setStatus(403);r.setCharacterEncoding("UTF-8");r.setContentType("application/json");r.getWriter().write("{\"error\":\"Authentication required\"}");}else r.sendRedirect(q.getContextPath()+"/login");return;}if(!allowed(path,u.getRoleName())){try{audit.recordEvent("ACCESS_DENIED",u.getUserId(),"PATH",null,q.getRemoteAddr(),q.getHeader("User-Agent"));}catch(RuntimeException ignored){}if(path.equals("/appointments/slots")){r.setStatus(403);r.setCharacterEncoding("UTF-8");r.setContentType("application/json");r.getWriter().write("{\"error\":\"Access denied\"}");}else r.sendError(403);return;}c.doFilter(a,b);}
private boolean allowed(String path,String role){if(path.equals("/schedules")||path.startsWith("/schedules/"))return Set.of("ADMIN","DOCTOR").contains(role);if(path.equals("/admin/patients")||path.startsWith("/admin/patients/"))return Set.of("ADMIN","RECEPTIONIST").contains(role);if(path.equals("/appointments/create")||path.equals("/appointments/slots")||path.equals("/appointments/reschedule"))return Set.of("ADMIN","RECEPTIONIST","PATIENT").contains(role);if(path.equals("/appointments/edit"))return Set.of("ADMIN","RECEPTIONIST","DOCTOR").contains(role);if(path.equals("/appointments")||path.startsWith("/appointments/"))return Set.of("ADMIN","RECEPTIONIST","DOCTOR","PATIENT").contains(role);return ACCESS.entrySet().stream().filter(e->path.startsWith(e.getKey())).allMatch(e->e.getValue().contains(role));}}
